// // This JK latch will set Q to 0 when J is high and K is low, reset Q to 1 when K is high and J is low, and keep Q unchanged if both J and K are high.
module JK_latch (
    input wire J,
    input wire K,
    input wire clk,
    output reg Q
);
    always @(posedge clk) begin
        if (J && !K)
            Q <= 1;
        else if (!J && K)
            Q <= 0;
        else if (J && K)
            Q <= ~Q; // toggle
    end
endmodule
